/*
 * 修复后的算法：基于最长递增子序列(LIS)计算最少轮数
 * 关键技术：将问题转化为寻找元素在目标序列中的位置顺序
 */
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    // 记录每个元素在目标序列中的位置（1-based）
    vector<int> pos(n + 1);
    for (int i = 0; i < n; ++i) {
        pos[a[i]] = i + 1;
    }

    // 计算LIS长度
    vector<int> lis;
    for (int i = 1; i <= n; ++i) {
        auto it = lower_bound(lis.begin(), lis.end(), pos[i]);
        if (it == lis.end()) {
            lis.push_back(pos[i]);
        } else {
            *it = pos[i];
        }
    }

    // 最少轮数 = 总长度 - LIS长度
    cout << max(0, n - (int)lis.size()) << endl;

    return 0;
}
```

