/* 最长回文拼接 - 优化后的版本 */
#include <bits/stdc++.h>
using namespace std;

bool is_palindrome(const string &s) {
    int l = 0, r = s.size() - 1;
    while (l < r) {
        if (s[l] != s[r]) return false;
        l++; r--;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<string> strs(n);
    unordered_map<string, int> str_map;  // 字符串到索引的映射
    unordered_set<string> rev_str_set;   // 所有字符串的逆序集合

    for (int i = 0; i < n; ++i) {
        cin >> strs[i];
        str_map[strs[i]] = i;
        string rev(strs[i].rbegin(), strs[i].rend());
        rev_str_set.insert(rev);
    }

    int max_len = 0;
    for (int i = 0; i < n; ++i) {
        const string &s = strs[i];
        string rev(s.rbegin(), s.rend());

        // 检查完全逆序匹配
        if (rev_str_set.count(s) && str_map.count(rev) && str_map[rev] != i) {
            max_len = max(max_len, (int)(s.size() + rev.size()));
        }

        // 检查部分逆序匹配
        // 情况1: t是s的前缀的逆序，且s的剩余部分是回文 (t + s是回文)
        for (int len = 1; len < s.size(); ++len) {
            string prefix = s.substr(0, len);
            string rev_prefix(prefix.rbegin(), prefix.rend());
            string remaining = s.substr(len);
            if (is_palindrome(remaining) && rev_str_set.count(rev_prefix) && 
                str_map.count(rev_prefix) && str_map[rev_prefix] != i) {
                max_len = max(max_len, (int)(rev_prefix.size() + s.size()));
                break;  // 只需要找到最长的有效前缀即可
            }
        }

        // 情况2: t是s的后缀的逆序，且s的前面部分是回文 (s + t是回文)
        for (int len = 1; len < s.size(); ++len) {
            string suffix = s.substr(s.size() - len);
            string rev_suffix(suffix.rbegin(), suffix.rend());
            string remaining = s.substr(0, s.size() - len);
            if (is_palindrome(remaining) && rev_str_set.count(rev_suffix) && 
                str_map.count(rev_suffix) && str_map[rev_suffix] != i) {
                max_len = max(max_len, (int)(s.size() + rev_suffix.size()));
                break;  // 只需要找到最长的有效后缀即可
            }
        }
    }

    cout << max_len << '\n';
    return 0;
}
